/**
 * Подтема SddsSbComTheme.OnDark
 */
@Composable
public fun SddsSbComTheme.OnDark(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalSddsSbComColors.current
    val overrideColors = currentColors.copyAttrs(OnDarkColorsOverride)
    val currentGradients = LocalSddsSbComGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnDarkGradientsOverride)
    SddsSbComTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
